import org.junit.Test;
import static org.junit.Assert.*;

public class CalculatorTest {

    @Test
    public void testAddition() {
        Calculator calculator = new Calculator();
        assertEquals(5, calculator.add(2, 3));
    }

    @Test
    public void testSubtraction() {
        Calculator calculator = new Calculator();
        assertEquals(1, calculator.sub(3, 2));
    }

    @Test
    public void testMultiplication() {
        Calculator calculator = new Calculator();
        assertEquals(6, calculator.mul(2, 3));
    }

    @Test
    public void testDivision() {
        Calculator calculator = new Calculator();
        assertEquals(2.0, calculator.div(4, 2), 0.0001);
    }

    @Test
    public void testDivisionByZero() {
        Calculator calculator = new Calculator();
        assertThrows(IllegalArgumentException.class, () -> {
            calculator.div(4, 0);
        });
    }

    @Test
    public void testInvalidInput() {
        Calculator calculator = new Calculator();
        assertThrows(IllegalArgumentException.class, () -> {
            calculator.add("a", 3);
        });
    }
}

import cement
from cement import handler
import logging
import os
import re

class ArithmeticApp(cement.App):
    class InfoHandler(handler.Handler):
        def get(self):
            self.app.log.info("Arithmetic App - Command-line Arithmetic Calculator")
            self.app.log.info("Available commands: add, subtract, multiply, divide")

    class AddHandler(handler.Handler):
        def get(self):
            self.app.log.info("Adding numbers...")
            try:
                a = float(self.app.input)
                b = float(self.app.input)
                result = a + b
                self.app.log.info(f"Result: {result}")
                self.app.log.info("Operation logged to history.")
                self.app.log.info("History file: %s" % self.app.config.get('log', 'file'))
                with open(self.app.config.get('log', 'file'), 'a') as f:
                    f.write(f"Add: {a} + {b} = {result}\n")
            except ValueError:
                self.app.log.error("Invalid input. Please enter numbers.")

    class SubtractHandler(handler.Handler):
        def get(self):
            self.app.log.info("Subtracting numbers...")
            try:
                a = float(self.app.input)
                b = float(self.app.input)
                result = a - b
                self.app.log.info(f"Result: {result}")
                self.app.log.info("Operation logged to history.")
                with open(self.app.config.get('log', 'file'), 'a') as f:
                    f.write(f"Subtract: {a} - {b} = {result}\n")
            except ValueError:
                self.app.log.error("Invalid input. Please enter numbers.")

    class MultiplyHandler(handler.Handler):
        def get(self):
            self.app.log.info("Multiplying numbers...")
            try:
                a = float(self.app.input)
                b = float(self.app.input)
                result = a * b
                self.app.log.info(f"Result: {result}")
                self.app.log.info("Operation logged to history.")
                with open(self.app.config.get('log', 'file'), 'a') as f:
                    f.write(f"Multiply: {a} * {b} = {result}\n")
            except ValueError:
                self.app.log.error("Invalid input. Please enter numbers.")

    class DivideHandler(handler.Handler):
        def get(self):
            self.app.log.info("Dividing numbers...")
            try:
                a = float(self.app.input)
                b = float(self.app.input)
                if b == 0:
                    self.app.log.error("Division by zero is not allowed.")
                else:
                    result = a / b
                    self.app.log.info(f"Result: {result}")
                    self.app.log.info("Operation logged to history.")
                    with open(self.app.config.get('log', 'file'), 'a') as f:
                        f.write(f"Divide: {a} / {b} = {result}\n")
            except ValueError:
                self.app.log.error("Invalid input. Please enter numbers.")

    def init(self):
        self.app.log.setLevel(logging.INFO)
        self.app.log.info("Arithmetic App initialized.")

if __name__ == "__main__":
    app = ArithmeticApp()
    app.run()

