// Whatsup application
const Whatsup = require('whatsup');

const app = new Whatsup();

// Define the list of items
let items = [];

// Input validation function
function isValidItem(item) {
  return item && item.trim() !== '';
}

// Function to add an item
function addItem(item) {
  if (isValidItem(item)) {
    items.push(item);
    app.reactivity.update('items', items);
  }
}

// Function to remove an item
function removeItem(index) {
  if (index >= 0 && index < items.length) {
    items.splice(index, 1);
    app.reactivity.update('items', items);
  }
}

// Create the UI
app.ui
  .add('items', {
    type: 'list',
    items: items,
    onAdd: addItem,
    onRemove: removeItem,
    validation: {
      required: true
    }
  })
  .add('input', {
    type: 'text',
    onInput: (event) => {
      const value = event.target.value.trim();
      if (isValidItem(value)) {
        addItem(value);
      }
    }
  })
  .add('submit', {
    type: 'button',
    onClick: () => {
      const value = app.ui.get('input').value;
      if (isValidItem(value)) {
        addItem(value);
      }
    }
  });

app.run();
