#include <cpputest-ng/unit_test.h>
#include <stdexcept>

class Calculator {
public:
    int add(int a, int b) {
        return a + b;
    }

    int subtract(int a, int b) {
        return a - b;
    }

    int multiply(int a, int b) {
        return a * b;
    }

    int divide(int a, int b) {
        if (b == 0) {
            throw std::domain_error("Division by zero");
        }
        return a / b;
    }
};

TEST_CASE("Calculator operations") {
    Calculator calc;

    // Test addition
    TEST_CASE("Addition of positive numbers", []() {
        int result = calc.add(5, 3);
        REQUIRE(result == 8);
    });

    TEST_CASE("Addition of negative numbers", []() {
        int result = calc.add(-2, 4);
        REQUIRE(result == 2);
    });

    TEST_CASE("Addition of zero", []() {
        int result = calc.add(0, 0);
        REQUIRE(result == 0);
    });

    // Test subtraction
    TEST_CASE("Subtraction of positive numbers", []() {
        int result = calc.subtract(5, 3);
        REQUIRE(result == 2);
    });

    TEST_CASE("Subtraction of negative numbers", []() {
        int result = calc.subtract(-2, 4);
        REQUIRE(result == -6);
    });

    TEST_CASE("Subtraction of zero", []() {
        int result = calc.subtract(0, 0);
        REQUIRE(result == 0);
    });

    // Test multiplication
    TEST_CASE("Multiplication of positive numbers", []() {
        int result = calc.multiply(5, 3);
        REQUIRE(result == 15);
    });

    TEST_CASE("Multiplication of negative numbers", []() {
        int result = calc.multiply(-2, 4);
        REQUIRE(result == -8);
    });

    TEST_CASE("Multiplication of zero", []() {
        int result = calc.multiply(0, 0);
        REQUIRE(result == 0);
    });

    // Test division
    TEST_CASE("Division of positive numbers", []() {
        int result = calc.divide(10, 2);
        REQUIRE(result == 5);
    });

    TEST_CASE("Division of negative numbers", []() {
        int result = calc.divide(-10, 2);
        REQUIRE(result == -5);
    });

    TEST_CASE("Division of zero by non-zero", []() {
        EXPECT_THROW(calc.divide(0, 0), std::domain_error);
    });

    TEST_CASE("Division of non-zero by zero", []() {
        EXPECT_THROW(calc.divide(10, 0), std::domain_error);
    });
}

