use bevy::prelude::*;
use bevy::window::Window;

fn main() {
    let mut app = App::new();
    app.add_plugins(DefaultPlugins);

    // Add window plugin
    app.add_plugin(WindowPlugin::default());

    // Create a window
    app.add_system(create_window_system)
        .add_system(handle_resize_system)
        .add_system(handle_close_system)
        .add_system(handle_color_input_system);

    // Initialize the window
    app.run();
}

fn create_window_system(mut window: ResMut<Window>) {
    window.set_title("Colored Rectangle");
    window.set_visible(true);
    window.set_position(ivec2(100, 100));
    window.set_inner_size(ivec2(800, 600));
}

fn handle_resize_system(mut window: ResMut<Window>) {
    // Handle window resize
    println!("Window resized to: {}", window.size());
}

fn handle_close_system(mut window: ResMut<Window>) {
    // Handle window close
    println!("Window is closing");
    window.close();
}

fn handle_color_input_system(
    mut input: ResMut<Input<KeyCode>>,
    mut rect: ResMut<Res<Rectangle>>,
    mut color: ResMut<Res<Color>>,
) {
    if input.just_pressed(KeyCode::Key1) {
        color.0 = Color::GREEN;
    } else if input.just_pressed(KeyCode::Key2) {
        color.0 = Color::RED;
    }
}
