use cot::prelude::*;
use serde::{Serialize, Deserialize};
use std::collections::BTreeSet;

#[derive(Serialize, Deserialize)]
struct Item {
    id: u32,
    name: String,
}

#[derive(Serialize, Deserialize)]
struct Response {
    items: BTreeSet<Item>,
}

#[derive(Debug, PartialEq)]
enum Error {
    InvalidInput,
    ServerError,
}

#[derive(Debug)]
struct AppState {
    items: BTreeSet<Item>,
}

#[derive(Debug)]
struct App {
    state: AppState,
}

impl App {
    fn new() -> Self {
        App { state: AppState { items: BTreeSet::new() } }
    }
}

#[derive(Debug)]
enum Endpoint {
    GET,
    POST,
}

#[derive(Debug)]
enum Method {
    GET,
    POST,
}

#[derive(Debug)]
enum Route {
    List,
    Add(Item),
}

impl<Route> Route {
    fn handle(&self, app: &mut App) -> Result<(), Error> {
        match self {
            Route::List => {
                let response = Response {
                    items: app.state.items.clone(),
                };
                Ok(response)
            }
            Route::Add(item) => {
                if item.name.is_empty() {
                    return Err(Error::InvalidInput);
                }
                app.state.items.insert(item);
                Ok(())
            }
        }
    }
}

#[derive(Debug)]
enum RouteError {
    InvalidInput,
    ServerError,
}

impl<Route> Route {
    fn handle_error(&self, err: &str) -> Result<(), RouteError> {
        if err.contains("empty") {
            return Err(RouteError::InvalidInput);
        }
        Err(RouteError::ServerError)
    }
}

fn main() {
    let app = App::new();
    let server = Server::new(8080);
    server.route(GET, "/").route(Route::List).handle(app);
    server.route(POST, "/").route(Route::Add).handle(app);
    server.start();
}
