    private EntityManager entityManager;

    @GET
    @Path("/{id}")
    @Produces(MediaType.APPLICATION_JSON)
    public Entity getEntity(@PathParam("id") Long id) {
        return entityManager.find(Entity.class, id);
    }

    @POST
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response createEntity(Entity entity) {
        entityManager.persist(entity);
        return Response.status(201).entity(entity).build();
    }

    @PUT
    @Path("/{id}")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response updateEntity(@PathParam("id") Long id, Entity entity) {
        entityManager.merge(entity);
        return Response.status(200).entity(entity).build();
    }

    @DELETE
    @Path("/{id}")
    public Response deleteEntity(@PathParam("id") Long id) {
        entityManager.remove(entityManager.find(Entity.class, id));
        return Response.status(200).build();
    }

    @GET
    @Produces(MediaType.APPLICATION_JSON)
    public Response getAllEntities() {
        List<Entity> entities = entityManager.createQuery("SELECT e FROM Entity e", Entity.class).getResultList();
        return Response.status(200).entity(entities).build();
