from flask import Flask, request, jsonify, abort
from datetime import datetime
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='book_api.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Define book data structure
class Book:
    def __init__(self, title, author, publication_date):
        self.title = title
        self.author = author
        self.publication_date = publication_date

# List to store books
books = []

# Validate publication date
def validate_publication_date(date_str):
    try:
        datetime.strptime(date_str, '%Y-%m-%d')
        return True
    except ValueError:
        return False

# Validate input
def validate_input(data):
    if not data:
        abort(400, description="Invalid input")
    if not all(key in data for key in ['title', 'author', 'publication_date']):
        abort(400, description="Missing required fields")
    if not validate_publication_date(data['publication_date']):
        abort(400, description="Invalid publication date format")

@app.route('/books', methods=['GET'])
def get_books():
    logging.info("GET request to /books")
    return jsonify([{
        'title': book.title,
        'author': book.author,
        'publication_date': book.publication_date.strftime('%Y-%m-%d')
    } for book in books])

@app.route('/books/<int:book_id>', methods=['GET'])
def get_book(book_id):
    logging.info(f"GET request to /books/{book_id}")
    book = next((b for b in books if b.id == book_id), None)
    if not book:
        abort(404, description="Book not found")
    return jsonify({
        'title': book.title,
        'author': book.author,
        'publication_date': book.publication_date.strftime('%Y-%m-%d')
    })

@app.route('/books', methods=['POST'])
def create_book():
    logging.info("POST request to /books")
    data = request.get_json()
    validate_input(data)
    new_book = Book(data['title'], data['author'], data['publication_date'])
    books.append(new_book)
    return jsonify({
        'message': 'Book created successfully',
        'book': {
            'title': new_book.title,
            'author': new_book.author,
            'publication_date': new_book.publication_date.strftime('%Y-%m-%d')
        }
    }), 201

@app.route('/books/<int:book_id>', methods=['PUT'])
def update_book(book_id):
    logging.info(f"PUT request to /books/{book_id}")
    book = next((b for b in books if b.id == book_id), None)
    if not book:
        abort(404, description="Book not found")
    data = request.get_json()
    validate_input(data)
    book.title = data['title']
    book.author = data['author']
    book.publication_date = datetime.strptime(data['publication_date'], '%Y-%m-%d')
    return jsonify({
        'message': 'Book updated successfully',
        'book': {
            'title': book.title,
            'author': book.author,
            'publication_date': book.publication_date.strftime('%Y-%m-%d')
        }
    }), 200

@app.route('/books/<int:book_id>', methods=['DELETE'])
def delete_book(book_id):
    logging.info(f"DELETE request to /books/{book_id}")
    book = next((b for b in books if b.id == book_id), None)
    if not book:
        abort(404, description="Book not found")
    books.remove(book)
    return jsonify({
        'message': 'Book deleted successfully'
    }), 200

