#include <iostream>
#include <vector>
#include <string>
#include <stdexcept>
#include <map>
#include <algorithm>

using namespace std;

class Task {
public:
    string name;
    vector<string> dependencies;
    bool isCompleted = false;

    Task(string name) : name(name) {}
};

class DAG {
private:
    map<string, Task*> tasks;
    map<string, bool> taskStatus;

public:
    void addTask(string name) {
        tasks[name] = new Task(name);
    }

    void addDependency(string taskName, string depName) {
        if (tasks.find(taskName) == tasks.end()) {
            throw invalid_argument("Task does not exist");
        }
        if (tasks.find(depName) == tasks.end()) {
            throw invalid_argument("Dependency does not exist");
        }
        tasks[taskName]->dependencies.push_back(depName);
    }

    void execute() {
        vector<string> order;
        for (auto& task : tasks) {
            if (!taskStatus[task.first]) {
                order.push_back(task.first);
            }
        }

        for (string task : order) {
            Task* current = tasks[task];
            current->isCompleted = true;
            taskStatus[task] = true;
        }
    }

    void printResults() {
        for (auto& task : tasks) {
            if (taskStatus[task.first]) {
                cout << "Task " << task.first << " completed." << endl;
            }
        }
    }
};

int main() {
    DAG graph;
    try {
        graph.addTask("Task1");
        graph.addTask("Task2");
        graph.addTask("Task3");

        graph.addDependency("Task2", "Task1");
        graph.addDependency("Task3", "Task2");

        graph.execute();
        graph.printResults();
    } catch (const invalid_argument& e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}

