use bevy::prelude::*;
use bevy::window::Window;

fn main() {
    // Initialize the Bevy engine
    let mut app = App::new();

    // Add the window asset
    app.add_asset(Window::default());

    // Add the basic entity
    app.add_systems(Startup, setup);
    app.add_systems(Update, update_game_state);
    app.add_systems(End, quit_game);

    // Run the application
    app.run();
}

fn setup(mut window: ResMut<Window>, mut commands: Commands) {
    // Create a simple entity (colored square)
    commands.spawn(Entity::default())
        .with_children(|mut children| {
            children.spawn(Sprite::default())
                .with_position(Vec2::new(100.0, 100.0))
                .with_color(Color::rgb(1.0, 0.0, 0.0));
        });
}

fn update_game_state(mut query: Query<(&mut Transform, &mut Color), (With<Entities>,)>) {
    // Update the game state (e.g., move the square)
    let (mut transform, mut color) = query.single_mut();
    transform.translation = Vec2::new(100.0, 100.0); // Reset position
    color.0 = Color::rgb(1.0, 0.0, 0.0); // Red color
}

fn quit_game(mut window: ResMut<Window>) {
    window.close();
}
