import cement
from cement import ex

class Calculator(cement.Cement):
    class App(cement.App):
        def initialize(self):
            self.register_command('calculate', self.calculate)

        def calculate(self, *args, **kwargs):
            if not args:
                ex.exit('Please provide an operation and two numbers.')

            op = args[0]
            a = float(args[1])
            b = float(args[2])

            if op == 'add':
                result = a + b
            elif op == 'subtract':
                result = a - b
            elif op == 'multiply':
                result = a * b
            elif op == 'divide':
                if b == 0:
                    ex.exit('Division by zero is not allowed.')
                result = a / b
            else:
                ex.exit(f'Invalid operation: {op}')

            print(f'Result: {result}')

if __name__ == '__main__':
    Cement().run()

