from flask import Flask, jsonify, request, abort
import logging

app = Flask(__name__)
app.logger.setLevel(logging.DEBUG)

# Task data
tasks = []

@app.route('/tasks', methods=['GET'])
def get_tasks():
    return jsonify({'tasks': tasks})

@app.route('/tasks/<int:task_id>', methods=['GET'])
def get_task(task_id):
    task = [t for t in tasks if t['id'] == task_id]
    if not task:
        abort(404)
    return jsonify(task)

@app.route('/tasks', methods=['POST'])
def create_task():
    if not request.json or not 'title' in request.json:
        abort(400)
    task = {
        'id': len(tasks) + 1,
        'title': request.json['title'],
        'completed': False
    }
    tasks.append(task)
    return jsonify(task), 201

@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    task = [t for t in tasks if t['id'] == task_id]
    if not task:
        abort(404)
    if 'title' in request.json and request.json['title'] is not None:
        task['title'] = request.json['title']
    if 'completed' in request.json and request.json['completed'] is not None:
        task['completed'] = request.json['completed']
    return jsonify(task)

@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    task = [t for t in tasks if t['id'] == task_id]
    if not task:
        abort(404)
    tasks.remove(task[0])
    return jsonify({'status': 'deleted'})

if __name__ == '__main__':
    app.run(port=5000)

from flask import Flask, request, jsonify, send_from_directory
import os
import uuid

app = Flask(__name__)

# Directory to store uploaded files
UPLOAD_FOLDER = 'uploads'
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Allowed file extensions
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'pdf', 'doc', 'docx'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1()].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    if not allowed_file(file.filename):
        return jsonify({"error": "Unsupported file type"}), 400

    # Generate unique filename
    filename = uuid.uuid4().hex + '.' + file.filename.rsplit('.', 1)[1()].lower()
    file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))

    # Return JSON response
    return jsonify({
        "file_path": os.path.join(app.config['UPLOAD_FOLDER'], filename),
        "upload_timestamp": str(os.path.getmtime(os.path.join(app.config['UPLOAD_FOLDER'], filename)))
    }), 200

@app.route('/files', methods=['GET'])
def list_files():
    files = os.listdir(app.config['UPLOAD_FOLDER'])
    file_paths = [os.path.join(app.config['UPLOAD_FOLDER'], f) for f in files]
    return jsonify({"files": file_paths}), 200

if __name__ == '__main__':
    app.run(debug=True)

import com.tinylog.Logger;
import java.io.*;
import java.util.*;

public class UserRegistrationApp {
    public static void main(String[] args) {
        // Read CSV file
        String csvFile = "userRegistrations.csv";
        List<String> lines = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            String line;
            while ((line = br.readLine()) != null) {
                lines.add(line);
            }
        } catch (IOException e) {
            Logger.error("Error reading CSV file: " + e.getMessage());
            return;
        }

        // Process each line
        for (String line : lines) {
            String[] fields = line.split(",");
            if (fields.length < 2) {
                Logger.error("Invalid line: " + line + " - missing fields");
                continue;
            }

            String name = fields[0];
            String email = fields[1];

            // Validate required fields
            if (name == null || name.isEmpty() || email == null || email.isEmpty()) {
                Logger.error("Invalid registration: " + name + " - " + email + " - missing fields");
                continue;
            }

            // Log registration status
            Logger.info("User " + name + " registered successfully at " + new Date());
        }
    }
}

