use bevy::prelude::*;
use bevy::sprite::Sprite;
use bevy::input::keyboard::KeyCode;

// Define the player character
#[derive(Component)]
struct Player {
    position: Vec2,
    health: i32,
}

// Define the obstacle
#[derive(Component)]
struct Obstacle {
    position: Vec2,
}

// Define the game state
#[derive(Component)]
struct GameState {
    is_game_over: bool,
    is_start_screen: bool,
}

// Define the start screen
#[derive(Component)]
struct StartScreen {
    is_visible: bool,
}

// Define the game-over screen
#[derive(Component)]
struct GameOverScreen {
    is_visible: bool,
}

// Handle keyboard input
fn handle_input(
    keyboard_input: Res<KeyboardInput>,
    mut player: Option<Entity>,
    mut obstacles: Query<(&mut Obstacle, &Transform)>,
    mut game_state: ResMut<AssetServer>,
) {
    if let Some(player_entity) = player {
        let keys = keyboard_input.keys;
        if keys.contains(KeyCode::KeyW) {
            // Move player up
            let mut pos = obstacles
                .iter_mut()
                .find(|(obstacle, _)| obstacle.position == player_entity.position)
                .map(|(_, transform)| transform.translation);
            if let Some(pos) = pos {
                player_entity.position = pos + Vec2::new(0, -1.0);
            }
        }
        if keys.contains(KeyCode::KeyS) {
            // Move player down
            let mut pos = obstacles
                .iter_mut()
                .find(|(obstacle, _)| obstacle.position == player_entity.position)
                .map(|(_, transform)| transform.translation);
            if let Some(pos) = pos {
                player_entity.position = pos + Vec2::new(0, 1.0);
            }
        }
        if keys.contains(KeyCode::KeyA) {
            // Move player left
            let mut pos = obstacles
                .iter_mut()
                .find(|(obstacle, _)| obstacle.position == player_entity.position)
                .map(|(_, transform)| transform.translation);
            if let Some(pos) = pos {
                player_entity.position = pos + Vec2::new(-1.0, 0.0);
            }
        }
        if keys.contains(KeyCode::KeyD) {
            // Move player right
            let mut pos = obstacles
                .iter_mut()
                .find(|(obstacle, _)| obstacle.position == player_entity.position)
                .map(|(_, transform)| transform.translation);
            if let Some(pos) = pos {
                player_entity.position = pos + Vec2::new(1.0, 0.0);
            }
        }
    }
}

// Collision detection
fn check_collision(
    mut player: Query<(&Player, &Transform)>,
    mut obstacles: Query<(&Obstacle, &Transform)>,
) {
    for (player_entity, player_pos) in &player {
        for (obstacle_entity, obstacle_pos) in &obstacles {
            if player_pos.distance(obstacle_pos) < 10.0 {
                // Collision detected
                // Reduce health
                player_entity.health -= 1;
                // If health is 0, game over
                if player_entity.health <= 0 {
                    // Game over screen
                    game_state.insert(GameState {
                        is_game_over: true,
                        is_start_screen: false,
                    });
                }
            }
        }
    }
}

// Start screen
fn start_screen(mut start_screen: Query<&mut StartScreen>) {
    start_screen
        .iter_mut()
        .for_each(|start_screen| *start_screen = true);
}

// Game over screen
fn game_over_screen(mut game_over_screen: Query<&mut GameOverScreen>) {
    game_over_screen
        .iter_mut()
        .for_each(|game_over_screen| *game_over_screen = true);
}

// Main game loop
fn main() {
    // Initialize the game
    let mut app = App::new();
    app.add_plugins(DefaultPlugins);
    app.add_systems(Startup, start_screen);
    app.add_systems(Update, handle_input);
    app.add_systems(Update, check_collision);
    app.add_systems(Update, game_over_screen);
    app.run();
}
