class ImageLoader : public CGraph::Node {
public:
    ImageLoader() : CGraph::Node("ImageLoader") {
        // Configure node
        setOutputType("image");
        setOutputName("output");
    }

    void execute() override {
        // Simulate image loading
        this->output = "image1.jpg";
        this->log("Loaded image: image1.jpg");
    }

    void log(const string& message) {
        // Log to file
        ofstream logFile("log.txt", ios::app);
        logFile << "[" << current_time() << "] " << message << endl;
