};

class ImageFilter : public CGraph::Node {
public:
    ImageFilter() : CGraph::Node("ImageFilter") {
        // Configure node
        setOutputType("grayscale");
        setOutputName("output");
    }

    void execute() override {
        // Simulate grayscale conversion
        this->output = "image1_grayscale.jpg";
        this->log("Applied grayscale to image: image1.jpg");
    }

    void log(const string& message) {
        // Log to file
        ofstream logFile("log.txt", ios::app);
        logFile << "[" << current_time() << "] " << message << endl;
        logFile.close();
    }

    string output;
    string output_name;
};

class ImageSaver : public CGraph::Node {
public:
    ImageSaver() : CGraph::Node("ImageSaver") {
        // Configure node
        setOutputType("output");
        setOutputName("output");
    }

    void execute() override {
        // Simulate saving
        this->output = "processed_image.jpg";
        this->log("Saved processed image: processed_image.jpg");
    }

    void log(const string& message) {
        // Log to file
        ofstream logFile("log.txt", ios::app);
        logFile << "[" << current_time() << "] " << message << endl;
        logFile.close();
    }

    string output;
    string output_name;
};

int main() {
    // Initialize CGraph
    CGraph graph;

    // Add nodes to the graph
    graph.addNode(new ImageLoader());
    graph.addNode(new ImageFilter());
    graph.addNode(new ImageSaver());

    // Connect nodes
    graph.connect("ImageLoader.output", "ImageFilter.input");
    graph.connect("ImageFilter.output", "ImageSaver.input");

    // Start the graph
    graph.start();

    // Wait for the graph to finish
    graph.join();

    // Get statistics
    map<string, double> stats;
    stats["ImageLoader"] = graph.getStat("ImageLoader.execution_time");
    stats["ImageFilter"] = graph.getStat("ImageFilter.execution_time");
    stats["ImageSaver"] = graph.getStat("ImageSaver.execution_time");

    // Output statistics in JSON format
    ofstream jsonFile("stats.json", ios::out);
    jsonFile << "{\n";
    for (const auto& [key, value] : stats) {
        jsonFile << "\"\" + key + \": \" + value + \",\n";
    }
    jsonFile << "}\n";
    jsonFile.close();

    return 0;
}

