import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.ServerInterceptor;
import io.grpc.stub.StreamObserver;
import io.prometheus.client.Counter;
import io.prometheus.client.Gauge;
import io.prometheus.client.Summary;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class InventoryService {

    private static final String SERVICE_NAME = "inventory-service";
    private static final String GRPC_PORT = "50051";
    private static final String METRICS_NAME = "inventory_metrics";
    private static final String RPC_CALL_COUNT = METRICS_NAME + ".call_count";
    private static final String RPC_CALL_DURATION = METRICS_NAME + ".call_duration";
    private static final String LOW_STOCK_ALERTS = METRICS_NAME + ".low_stock_alerts";

    private static final Gauge CALL_COUNT_GAUGE = Gauge.build()
            .name(RPC_CALL_COUNT)
            .help("Number of RPC calls made")
            .register();

    private static final Summary CALL_DURATION_SUMMARY = Summary.build()
            .name(RPC_CALL_DURATION)
            .help("Duration of RPC calls in milliseconds")
            .register();

    private static final Gauge LOW_STOCK_ALERTS_GAUGE = Gauge.build()
            .name(LOW_STOCK_ALERTS)
            .help("Number of low-stock alerts generated")
            .register();

    public static void main(String[] args) {
        Server server = ServerBuilder.forPort(50051)
                .addService(new InventoryServiceImpl())
                .intercept(new ServerInterceptor() {
                    @Override
                    public <In, Out> StreamObserver<In> interceptStreamObserver(
                            StreamObserver<Out> streamObserver) {
                        return new StreamObserver<Out>() {
                            @Override
                            public void onNext(In message) {
                                // Handle unary call
                                handleUnaryCall(message);
                            }

                            @Override
                            public void onError(Throwable t) {
                                streamObserver.onError(t);
                            }

                            @Override
                            public void onCompleted() {
                                streamObserver.onCompleted();
                            }
                        };
                    }
                })
                .build();

        ManagedChannel channel = ManagedChannelBuilder.forAddress("localhost", 50051)
                .usePlaintext()
                .build();

        try {
            server.start();
            System.out.println("Server started on port " + GRPC_PORT);
            Thread.sleep(Long.MAX_VALUE);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
    }

    private static void handleUnaryCall(StreamObserver<InventoryResponse> observer) {
        // Simulate a unary call
        InventoryResponse response = InventoryResponse.newBuilder()
                .setStock(100)
                .build();
        observer.onNext(response);
        observer.onCompleted();
    }

    // Server streaming implementation
    private static class InventoryServiceImpl extends InventoryServiceGrpc.InventoryServiceImplBase {
        @Override
        public void streamLowStockAlerts(InventoryRequest request, StreamObserver<InventoryResponse> responseObserver) {
            // Simulate server streaming
            for (int i = 0; i < 5; i++) {
                InventoryResponse response = InventoryResponse.newBuilder()
                        .setStock(90 - i)
                        .build();
                responseObserver.onNext(response);
                try {
                    Thread.sleep(1000);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    responseObserver.onError(e);
                }
            }
            responseObserver.onCompleted();
        }
    }

    // Health check method
    public void checkHealth() {
        // Simulate health check
        System.out.println("Service is healthy");
    }

    // TLS-secured communication
    public void secureCommunication() {
        // Implement TLS configuration
    }

    // Metrics collection
    public void collectMetrics() {
        CALL_COUNT_GAUGE.inc();
        CALL_DURATION_SUMMARY.observe(100);
        LOW_STOCK_ALERTS_GAUGE.inc();
    }
}
