const Whatsup = () => {
  // Custom hook for tracking user engagement metrics
  const useEngagement = () => {
    const [likes, setLikes] = useState(0);
    const [comments, setComments] = useState(0);
    const [likesCount, setLikesCount] = useState(0);

    const likePost = () => {
      setLikes(prev => prev + 1);
      setLikesCount(prev => prev + 1);
    };

    const commentPost = () => {
      setComments(prev => prev + 1);
      setLikesCount(prev => prev + 1);
    };

    return { likes, comments, likesCount, likePost, commentPost };
  };

  // Generator for lazy loading posts
  const postGenerator = () => {
    let index = 0;
    return {
      next: () => {
        if (index < 5) {
          const post = {
            id: index,
            content: `Post ${index}`,
            likes: 10,
            comments: 5,
            timestamp: new Date().toISOString()
          };
          index++;
          return { value: post, done: false };
        }
        return { value: null, done: true };
      },
      return: () => {
        index = 5;
      }
    };
  };

  // Component for Feed
  const Feed = () => {
    const { likes, comments, likesCount, likePost, commentPost } = useEngagement();
    const posts = postGenerator();

    return (
      <div>
        <h1>Whatsup</h1>
        <div>
          {Array.from({ length: 5 }).map((_, i) => (
            <div key={i} className="post">
              <div className="post-content">
                <p>{`Post ${i + 1}`}</p>
                <div className="post-actions">
                  <button onClick={likePost}>Like ({likesCount})</button>
                  <button onClick={commentPost}>Comment ({comments})</button>
                </div>
              </div>
              <div className="post-stats">
                <span> Likes: {likes} </span>
                <span> Comments: {comments} </span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // Component for Post
  const Post = ({ post }) => {
    const { likes, comments, likesCount, likePost, commentPost } = useEngagement();

    return (
      <div className="post">
        <div className="post-header">
          <h2>{post.content}</h2>
          <div className="post-stats">
            <span> Likes: {post.likes} </span>
            <span> Comments: {post.comments} </span>
          </div>
        </div>
        <div className="post-body">
          <div className="post-actions">
            <button onClick={likePost}>Like ({likesCount})</button>
            <button onClick={commentPost}>Comment ({comments})</button>
          </div>
        </div>
      </div>
    );
  };

  // Component for CommentSection
  const CommentSection = ({ comments }) => {
    return (
      <div className="comment-section">
        {comments.map((comment, index) => (
          <div key={index} className="comment">
            <p>{comment.text}</p>
          </div>
        ))}
      </div>
    );
  };

  return (
    <div>
      <Feed />
      <CommentSection />
    </div>
  );
};

export default Whatsup;

