// Test class for sensor data validation
class SensorDataValidator : public CPPUNIT_TEST_SUITE_ENTRY {
public:
    SensorDataValidator() {
        CPPUNIT_TEST_SUITE_INIT("SensorDataValidator");
        CPPUNIT_TEST_CASE(ValidateBoundary);
        CPPUNIT_TEST_CASE(ValidateDataFormat);
        CPPUNIT_TEST_CASE(ValidateChecksum);
        CPPUNIT_TEST_CASE(ValidateHardwareInterface);
        CPPUNIT_TEST_CASE(ValidateParameterized);
        CPPUNIT_TEST_CASE(ValidateMemoryLeak);
        CPPUNIT_TEST_CASE(ValidateTestSetupTeardown);
        CPPUNIT_TEST_CASE(ValidateXMLReport);
        CPPUNIT_TEST_SUITE_END();
    }

    void ValidateBoundary() {
        // Boundary check for valid range
        std::vector<int> data = { -100, 100 };
        CPPUNIT_ASSERT_EQUAL(true, ValidateData(data));
        // Boundary check for invalid range
        data = { 200, 300 };
        CPPUNIT_ASSERT_EQUAL(false, ValidateData(data));
    }

    void ValidateDataFormat() {
        // Check data format validation
        std::vector<int> data = { 123, 456 };
        CPPUNIT_ASSERT_EQUAL(true, ValidateData(data));
        data = { 123, 456, 789 };
        CPPUNIT_ASSERT_EQUAL(true, ValidateData(data));
    }

    void ValidateChecksum() {
        // Check checksum verification
        std::vector<int> data = { 1, 2, 3, 4 };
        int checksum = 10;
        CPPUNIT_ASSERT_EQUAL(true, ValidateChecksum(data, checksum));
        data = { 1, 2, 3, 5 };
        checksum = 11;
        CPPUNIT_ASSERT_EQUAL(true, ValidateChecksum(data, checksum));
    }

    void ValidateHardwareInterface() {
        // Test hardware interface with test doubles
        auto mockHardware = std::make_shared<MockHardware>();
        auto validator = SensorDataValidator::CreateValidator(mockHardware);
        CPPUNIT_ASSERT(validator->ValidateData({ 1, 2, 3 }));
    }

    void ValidateParameterized() {
        // Parameterized tests for different sensor types
        std::vector<std::pair<std::string, bool>> testCases = {
            {"TemperatureSensor", true},
            {"HumiditySensor", true},
            {"PressureSensor", false}
        };

        for (const auto& [sensorType, expected] : testCases) {
            auto validator = SensorDataValidator::CreateValidator(sensorType);
            CPPUNIT_ASSERT_EQUAL(expected, validator->ValidateData({ 1, 2, 3 }));
        }
    }

    void ValidateMemoryLeak() {
        // Memory leak detection
        std::shared_ptr<MockHardware> mockHardware = std::make_shared<MockHardware>();
        auto validator = SensorDataValidator::CreateValidator(mockHardware);
        CPPUNIT_ASSERT_NO_LEAK(validator);
    }

    void ValidateTestSetupTeardown() {
        // Test setup/teardown methods
        auto validator = SensorDataValidator::CreateValidator();
        CPPUNIT_ASSERT(validator->Setup());
        CPPUNIT_ASSERT(validator->Teardown());
    }

    void ValidateXMLReport() {
        // Generate XML test reports
        auto validator = SensorDataValidator::CreateValidator();
        CPPUNIT_ASSERT(validator->GenerateXMLReport("test_report.xml"));
    }

    bool ValidateData(const std::vector<int>& data) {
        // Simple data validation
        if (data.size() < 2) {
            throw std::invalid_argument("Data must have at least two elements");
        }
        if (data[0] < -100 || data[0] > 100) {
            throw std::invalid_argument("Invalid range for first element");
        }
        if (data[1] < 0 || data[1] > 255) {
            throw std::invalid_argument("Invalid range for second element");
        }
        return true;
    }

    int ValidateChecksum(const std::vector<int>& data, int expectedChecksum) {
        // Simple checksum calculation
        int currentChecksum = 0;
        for (int val : data) {
            currentChecksum += val;
        }
        return currentChecksum;
    }

    static std::shared_ptr<SensorDataValidator> CreateValidator(const std::string& sensorType) {
        return std::make_shared<SensorDataValidator>();
    }

    static std::shared_ptr<SensorDataValidator> CreateValidator(const std::shared_ptr<MockHardware>& hardware) {
        return std::make_shared<SensorDataValidator>();
    }
};

// Mock hardware interface
