          <span v-if="task.status === 'Done'">[[Done]] </span>
          {{ task.text }}
          <button @click="editTask(index)">Edit</button>
          <button @click="deleteTask(index)">Delete</button>
        </li>
      </ul>
    </div>
    <div v-else>
      <p>No tasks found.</p>
    </div>
  </div>
