<script>
export default {
  data() {
    return {
      newTask: "",
      tasks: [
        { id: 1, text: "Task 1", status: "To Do" },
        { id: 2, text: "Task 2", status: "In Progress" },
        { id: 3, text: "Task 3", status: "Done" }
      ]
    };
  },
  methods: {
    addTask() {
      if (this.newTask.trim()) {
        this.tasks.push({
          id: this.tasks.length + 1,
          text: this.newTask,
          status: "To Do"
        });
        this.newTask = "";
      }
    },
    editTask(index) {
      this.tasks[index].text = this.newTask;
      this.newTask = "";
    },
    deleteTask(index) {
      this.tasks.splice(index, 1);
    }
  }
};
