from flask import Flask, render_template, request, redirect, url_for, flash
from flask_sqlalchemy import SQLAlchemy
from flask_wtf.csrf import CSRFProtect
from wtforms import Form, StringField, PasswordField, validators
from jinja2 import Environment, FileSystemLoader
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///document.db'
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['INSTANCE_FOLDER'] = 'instance'
app.config['ENV'] = 'development'

csrf = CSRFProtect(app)

db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)
    role = db.Column(db.String(20), nullable=False)

class Document(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(200), nullable=False)
    content = db.Column(db.Text, nullable=False)
    file_path = db.Column(db.String(200), nullable=False)
    metadata = db.Column(db.JSON, nullable=True)

class DocumentForm(Form):
    title = StringField('Title', [validators.required()])
    content = StringField('Content', [validators.required()])
    file = FileField('File', [validators.optional()])

# Create database
with app.app_context():
    db.create_all()

@app.route('/')
def home():
    return render_template('home.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    form = DocumentForm(request.form)
    if request.method == 'POST':
        # Validate form
        if form.validate():
            # Check user exists and role
            user = User.query.filter_by(username=form.title.data).first()
            if user:
                if user.role == 'admin':
                    return redirect(url_for('dashboard'))
                else:
                    return redirect(url_for('user_dashboard'))
            else:
                flash('User not found')
        else:
            flash('Form validation failed')
    return render_template('login.html', form=form)

@app.route('/upload', methods=['GET', 'POST'])
def upload():
    form = DocumentForm(request.form)
    if request.method == 'POST':
        if form.validate():
            file = request.files['file']
            if file:
                filename = file.filename
                file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
                doc = Document(title=form.title.data, content=form.content.data, file_path=filename, metadata={})
                db.session.add(doc)
                db.session.commit()
                return redirect(url_for('upload_success'))
        else:
            flash('Form validation failed')
    return render_template('upload.html', form=form)

@app.route('/upload_success')
def upload_success():
    return render_template('upload_success.html')

@app.route('/user_dashboard')
def user_dashboard():
    documents = Document.query.filter_by(role='user').all()
    return render_template('user_dashboard.html', documents=documents)

@app.route('/admin_dashboard')
def admin_dashboard():
    documents = Document.query.all()
    return render_template('admin_dashboard.html', documents=documents)

@app.route('/preview/<filename>')
def preview(filename):
    return render_template('preview.html', filename=filename)

@app.route('/audit_log')
def audit_log():
    return render_template('audit_log.html')

if __name__ == '__main__':
    app.run(debug=True)

