const express = require('express');
const app = express();
const port = 3000;

app.get('/user/:id', (req, res) => {
  const userId = req.params.id;
  // Simulate fetching user data
  const user = {
    id: userId,
    name: 'John Doe',
    email: 'john.doe@example.com'
  };
  res.json(user);
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});

